def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent sentence. Uses relative clauses to create coherent complex sentences.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    def _format_predicate(s: str, p: str, o: str) -> str:
        """Format a triple into natural language."""
        o = _clean(o)

        if p == "cityServed":
            return f"{s} serves the city of {o}"
        elif p == "location":
            return f"{s} is located in {o}"
        elif p == "country":
            return f"{s} is in {o}"
        elif p == "isPartOf":
            return f"{s} is part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            return f"{s} has an elevation of {o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} has an elevation of {o} feet above sea level"
        elif p == "elevationAboveTheSeaLevelInMetres":
            return f"{s} has an elevation of {o} metres above sea level"
        elif p == "operatingOrganisation":
            return f"{s} is operated by {o}"
        elif p == "runwaySurfaceType":
            return f"{s} has runway surface {o}"
        elif p == "runwayName":
            return f"{s} has runway name {o}"
        elif p == "runwayLength":
            return f"{s} has a runway length of {o}"
        elif p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}"
        elif p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}"
        elif p == "locationIdentifier":
            return f"{s} has location identifier {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0].lower()
            return f"{s} has {idx} runway of {o} feet"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0].lower()
            return f"{s} has {idx} runway of {o} metres"
        elif p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0].lower()
            return f"{s} has {idx} runway surface {o}"
        elif p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0].lower()
            return f"{s} has {idx} runway number {o}"
        elif p == "nativeName":
            return f"{s} is known locally as {o}"
        elif p == "owner":
            return f"{s} is owned by {o}"
        elif p == "capital":
            return f"{s}'s capital is {o}"
        elif p == "language":
            return f"{s} speaks {o}"
        elif p == "officialLanguage":
            return f"{s}'s official language is {o}"
        elif p == "currency":
            return f"{s} uses {o}"
        elif p == "demonym":
            return f"{s}'s people are called {o}"
        elif p == "largestCity":
            return f"{s}'s largest city is {o}"
        elif p == "countySeat":
            return f"{s}'s county seat is {o}"
        elif p == "leader":
            return f"{s}'s leader is {o}"
        elif p == "mayor":
            return f"{s}'s mayor is {o}"
        elif p == "administrativeArrondissement":
            return f"{s} is in the {o}"
        elif p == "ceremonialCounty":
            return f"{s} is in {o}"
        elif p == "areaCode":
            return f"{s}'s area code is {o}"
        elif p == "postalCode":
            return f"{s}'s postal code is {o}"
        elif p == "foundingYear":
            return f"{s} was founded in {o}"
        elif p == "foundedBy":
            return f"{s} was founded by {o}"
        elif p == "headquarter":
            return f"{s} has headquarters at {o}"
        elif p == "jurisdiction":
            return f"{s} has jurisdiction over {o}"
        elif p == "regionServed":
            return f"{s} serves the {o} region"
        elif p == "hubAirport":
            return f"{s} has hub airport at {o}"
        elif p == "city":
            return f"{s} is located in {o}"
        elif p == "division":
            return f"{s} is a type of {o}"
        elif p == "order":
            return f"{s} belongs to order {o}"
        elif p == "class":
            return f"{s} belongs to class {o}"
        else:
            return f"{s} has {p.replace('_', ' ')} {o}"

    # Group triples by subject to build coherent sentences
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main subject (usually the airport)
    main_subject = triples[0].subject if triples else ""
    other_subjects = [s for s in subject_triples.keys() if s != main_subject]

    # Build the main sentence from main subject triples
    main_parts = []
    for t in triples:
        if t.subject == main_subject:
            main_parts.append(_format_predicate(t.subject, t.predicate, t.object))

    # Build the sentence with relative clauses
    if main_parts:
        # Start with the first part
        sentence = main_parts[0]

        # Add remaining parts with appropriate connectors
        for i, part in enumerate(main_parts[1:], 1):
            if i == 1:
                sentence += ", " + part
            else:
                sentence += ", and " + part

        # Add information about other subjects with relative clauses
        for other_subj in other_subjects:
            other_triples = subject_triples[other_subj]
            other_parts = [_format_predicate(other_subj, t.predicate, t.object) for t in other_triples]
            if other_parts:
                # Use relative clause to connect
                sentence += f", where {other_parts[0]}"
                for part in other_parts[1:]:
                    sentence += f", and {part}"

        sentence += "."
        return sentence[0].upper() + sentence[1:]

    return ""

# EVOLVE-BLOCK-END

